    63→        deposit_paid BOOLEAN DEFAULT FALSE,
    64→        comments TEXT,
    65→        created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    66→        updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
    67→      );
    68→    `);
    69→
    70→    await client.query(`
    71→      CREATE TABLE IF NOT EXISTS commission_rules (
    72→        id VARCHAR(50) PRIMARY KEY,
    73→        base_salary NUMERIC(12,2) NOT NULL,
    74→        per_booking NUMERIC(12,2) NOT NULL,
    75→        per_deposit_collected NUMERIC(12,2) NOT NULL,
    76→        per_show_up NUMERIC(12,2) NOT NULL,
    77→        target_bookings INT NOT NULL,
    78→        bonus_amount NUMERIC(12,2) NOT NULL,
    79→        updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
    80→      );
    81→    `);
    82→
    83→    await client.query(`
    84→      CREATE TABLE IF NOT EXISTS marketing_users (
