    86→        role VARCHAR(50) NOT NULL,
    87→        pin VARCHAR(100) NOT NULL,
    88→        department VARCHAR(255) NOT NULL,
    89→        bio TEXT,
    90→        avatar_color VARCHAR(100) NOT NULL,
    91→        status VARCHAR(50) DEFAULT 'offline',
    92→        last_active VARCHAR(100)
    93→      );
    94→    `);
    95→
    96→    const rulesCount = await client.query('SELECT COUNT(*) FROM commission_rules');
    97→    if (parseInt(rulesCount.rows[0].count) === 0) {
    98→      await client.query(
    99→        `INSERT INTO commission_rules (id, base_salary, per_booking, per_deposit_collected, per_show_up, target_bookings, bonus_amount)
   100→         VALUES ('default', $1, $2, $3, $4, $5, $6)`,
   101→        [DEFAULT_RULES.baseSalary, DEFAULT_RULES.perBooking, DEFAULT_RULES.perDepositCollected,
   102→         DEFAULT_RULES.perShowUp, DEFAULT_RULES.targetBookings, DEFAULT_RULES.bonusAmount]
   103→      );
   104→    }
   105→
   106→    const usersCount = await client.query('SELECT COUNT(*) FROM marketing_users');
   107→    if (parseInt(usersCount.rows[0].count) === 0) {
   108→      for (const u of DEFAULT_USERS) {
   109→        await client.query(
   110→          `INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color, status, last_active)
   111→           VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
   112→          [u.name, u.role, u.pin, u.department, u.bio, u.avatarColor, u.status, u.lastActive]
   113→        );
   114→      }
   115→    }
   116→
   117→    client.release();
   118→    db.isConnected = true;
   119→    db.status.configured = true;
   120→    db.status.error = '';
   121→    console.log('[DB] Tables bootstrapped successfully.');
   122→  } catch (err: any) {
   123→    db.isConnected = false;
   124→    db.status.configured = false;
   125→    db.status.error = `Connection failed: ${err.message}`;
   126→    console.error('[DB] Bootstrap failed:', err);
   127→  }
   128→}
