     1→import { Router } from 'express';
     2→import { db } from '../db';
     3→import { readLocalUsers, writeLocalUsers } from '../localFallback';
     4→
     5→const router = Router();
     6→
     7→// In-memory rate limiter: max 10 attempts per IP per minute
     8→// NOTE: For multi-instance deployments, replace with Redis-backed rate limiting
     9→const attempts = new Map<string, { count: number; resetAt: number }>();
    10→
    11→function checkRateLimit(ip: string): boolean {
    12→  const now = Date.now();
    13→  const entry = attempts.get(ip);
    14→  if (!entry || entry.resetAt < now) {
    15→    attempts.set(ip, { count: 1, resetAt: now + 60_000 });
    16→    return true;
    17→  }
    18→  if (entry.count >= 10) return false;
    19→  entry.count++;
    20→  return true;
    21→}
    22→
    23→// POST /api/auth/login
    24→router.post('/login', async (req, res) => {
    25→  const ip = req.ip || req.socket.remoteAddress || 'unknown';
    26→  if (!checkRateLimit(ip)) {
    27→    return res.status(429).json({ success: false, error: 'Слишком много попыток. Подождите минуту.' });
    28→  }
    29→
    30→  const { name, pin } = req.body;
    31→  if (!pin) {
    32→    return res.status(400).json({ success: false, error: 'ПИН-код обязателен' });
    33→  }
    34→
    35→  let matchedUser: any = null;
    36→
    37→  if (db.pool && db.isConnected) {
    38→    try {
    39→      const query = name
    40→        ? 'SELECT * FROM marketing_users WHERE name = $1 AND pin = $2'
    41→        : 'SELECT * FROM marketing_users WHERE pin = $1';
    42→      const params = name ? [name, pin] : [pin];
    43→      const result = await db.pool.query(query, params);
    44→
    45→      if (result.rows.length > 0) {
    46→        const row = result.rows[0];
    47→        matchedUser = {
    48→          name: row.name, role: row.role, pin: row.pin,
    49→          department: row.department, bio: row.bio,
    50→          avatarColor: row.avatar_color, status: 'online', lastActive: 'В сети',
    51→        };
    52→        await db.pool.query(
    53→          'UPDATE marketing_users SET status = $1, last_active = $2 WHERE name = $3',
    54→          ['online', 'В сети', row.name]
    55→        );
    56→      }
    57→    } catch (err) {
    58→      console.error('[Auth] DB login error:', err);
    59→    }
    60→  }
    61→
    62→  if (!matchedUser) {
    63→    const users = readLocalUsers();
    64→    matchedUser = name
    65→      ? users.find((u: any) => u.name === name && u.pin === pin)
    66→      : users.find((u: any) => u.pin === pin);
    67→
    68→    if (matchedUser) {
    69→      const idx = users.findIndex((u: any) => u.name === matchedUser.name);
    70→      if (idx >= 0) {
    71→        users[idx].status = 'online';
    72→        users[idx].lastActive = 'В сети';
    73→        writeLocalUsers(users);
    74→      }
    75→    }
    76→  }
    77→
    78→  if (matchedUser) {
    79→    return res.json({ success: true, user: matchedUser });
    80→  }
    81→  res.status(401).json({ success: false, error: 'Неверный ПИН-код' });
    82→});
    83→
    84→// POST /api/auth/logout
    85→router.post('/logout', async (req, res) => {
    86→  const { name } = req.body;
    87→  if (!name) return res.json({ success: true });
    88→
    89→  const lastActive = new Date().toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' }) + ' назад';
    90→
    91→  if (db.pool && db.isConnected) {
    92→    try {
    93→      await db.pool.query(
    94→        'UPDATE marketing_users SET status = $1, last_active = $2 WHERE name = $3',
    95→        ['offline', lastActive, name]
    96→      );
    97→    } catch (err) {
    98→      console.error('[Auth] DB logout error:', err);
    99→    }
   100→  } else {
   101→    const users = readLocalUsers();
   102→    const idx = users.findIndex((u: any) => u.name === name);
   103→    if (idx >= 0) {
   104→      users[idx].status = 'offline';
   105→      users[idx].lastActive = lastActive;
   106→      writeLocalUsers(users);
   107→    }
   108→  }
   109→  res.json({ success: true });
   110→});
   111→
   112→export default router;
