    <header className="bg-white/70 backdrop-blur-md border-b border-neutral-100/30 px-6 py-5 shrink-0 shadow-sm">
      <div className="flex items-center gap-2 text-[8.5px] text-neutral-400 font-bold uppercase tracking-widest">
