import React, { useState, useEffect } from 'react';
import { LeadReport, LeadStatus, StaffMember } from '../types';
import { Link, Calendar, Phone, User, FileText, Check, X, ChevronDown } from 'lucide-react';

interface LeadFormProps {
  initialLead?: LeadReport | null;
  onSave: (lead: LeadReport) => Promise<boolean>;
  onCancel?: () => void;
  currentUserRole: 'admin' | 'manager';
  currentManagerName: string;
  staffList: StaffMember[];
}

export default function LeadForm({ 
  initialLead, 
  onSave, 
  onCancel, 
  currentUserRole, 
  currentManagerName,
  staffList
}: LeadFormProps) {
  const [managerName, setManagerName] = useState(initialLead?.managerName || '');
  const [clientName, setClientName] = useState(initialLead?.clientName || '');
  const [clientPhone, setClientPhone] = useState(initialLead?.clientPhone || '');
  const [amocrmLeadId, setAmocrmLeadId] = useState(initialLead?.amocrmLeadId || '');
  const [bookingDate, setBookingDate] = useState(initialLead?.bookingDate || new Date().toISOString().split('T')[0]);
  const [status, setStatus] = useState<LeadStatus>(initialLead?.status || 'booked');
  const [depositRequired, setDepositRequired] = useState(initialLead?.depositRequired || false);
  const [depositAmount, setDepositAmount] = useState(initialLead?.depositAmount || 0);
  const [depositPaid, setDepositPaid] = useState(initialLead?.depositPaid || false);
  const [comments, setComments] = useState(initialLead?.comments || '');

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const managersOnly = staffList.filter(u => u.role === 'manager');

  useEffect(() => {
    if (currentUserRole === 'manager') {
      setManagerName(currentManagerName);
    } else if (!initialLead) {
      setManagerName('');
    }
  }, [currentUserRole, currentManagerName, initialLead]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess(false);

    let finalManager = managerName;
    if (currentUserRole === 'manager') {
      finalManager = currentManagerName;
    }

    if (!finalManager || finalManager.trim() === '') {
      setError('Пожалуйста, выберите ответственного менеджера из списка');
      return;
    }
    if (!clientName || clientName.trim() === '') {
      setError('Имя клиента является обязательным полем');
      return;
    }
    if (!bookingDate) {
      setError('Укажите дату записи');
      return;
    }

    setIsLoading(true);

    const payload: LeadReport = {
      id: initialLead?.id,
      managerName: finalManager.trim(),
      clientName: clientName.trim(),
      clientPhone: clientPhone.trim(),
      amocrmLeadId: amocrmLeadId.trim(),
      bookingDate,
      status,
      depositRequired,
      depositAmount: depositRequired ? depositAmount : 0,
      depositPaid: depositRequired ? depositPaid : false,
      comments: comments.trim()
    };

    const isOk = await onSave(payload);
    setIsLoading(false);

    if (isOk) {
      setSuccess(true);
      if (!initialLead) {
        setClientName('');
        setClientPhone('');
        setAmocrmLeadId('');
        setDepositRequired(false);
        setDepositAmount(0);
        setDepositPaid(false);
        setComments('');
      }
      setTimeout(() => setSuccess(false), 2000);
    } else {
      setError('Сбой сохранения данных. Пожалуйста, попробуйте еще раз.');
    }
  };

  const inputClass = "w-full px-4 py-3 bg-white border border-indigo-100 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-100 focus:outline-none text-neutral-900 font-medium rounded-xl transition-colors duration-150 text-sm placeholder:text-neutral-300";
  const inputWithIconClass = "w-full pl-10 pr-4 py-3 bg-white border border-indigo-100 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-100 focus:outline-none text-neutral-900 font-medium rounded-xl transition-colors duration-150 text-sm placeholder:text-neutral-300";
  const labelClass = "block text-[10px] font-bold uppercase tracking-widest text-indigo-400 mb-1.5";
  const iconClass = "absolute left-3.5 top-3.5 w-4 h-4 text-indigo-300";

  return (
    <div className="p-7 relative">
      {/* Header */}
      <div className="pb-5 border-b border-indigo-50 flex items-center justify-between gap-4">
        <div>
          <h4 className="font-display font-bold text-neutral-900 text-base flex items-center gap-2">
            <span className="text-xl">{initialLead ? '🖋️' : '📝'}</span>
            <span>{initialLead ? 'Редактирование записи' : 'Карточка записи'}</span>
          </h4>
        </div>
        {onCancel && (
          <button
            type="button"
            onClick={onCancel}
            className="p-2 rounded-xl border border-neutral-100 text-neutral-400 hover:text-neutral-700 hover:border-neutral-200 hover:bg-neutral-50 transition-colors duration-150 cursor-pointer"
          >
            <X className="w-4 h-4" />
          </button>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-5 pt-5">
        {error && (
          <div className="p-3 bg-red-50 border border-red-100 text-red-700 text-xs rounded-xl font-semibold text-center">
            {error}
          </div>
        )}
        {success && (
          <div className="p-3 bg-emerald-50 border border-emerald-200 text-emerald-700 text-xs rounded-xl font-semibold flex items-center gap-2">
            <Check className="w-4 h-4 text-emerald-500 shrink-0" />
            <span>Запись успешно сохранена!</span>
          </div>
        )}

        {/* Row 1: Manager + Client */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div>
            <label className={labelClass}>Ответственный менеджер *</label>
            {currentUserRole === 'admin' ? (
              <div className="relative">
                <select
                  value={managerName}
                  onChange={(e) => setManagerName(e.target.value)}
                  className="w-full px-4 py-3 bg-white border border-indigo-100 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-100 focus:outline-none text-neutral-900 font-medium rounded-xl transition-colors duration-150 text-sm cursor-pointer appearance-none pr-10"
                >
                  <option value="">— Выбрать сотрудника —</option>
                  {managersOnly.map(pm => (
                    <option key={pm.name} value={pm.name}>{pm.name}</option>
                  ))}
                  <option value="custom">Новый сотрудник вручную...</option>
                </select>
                <ChevronDown className="absolute right-3.5 top-3.5 w-4 h-4 text-indigo-300 pointer-events-none" />
              </div>
            ) : (
              <div className="px-4 py-3 bg-indigo-50 border border-indigo-100 rounded-xl text-indigo-900 font-semibold flex items-center justify-between text-sm">
                <span className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-emerald-500" />
                  👤 {currentManagerName}
                </span>
                <span className="text-[9px] bg-indigo-600 text-white px-2 py-0.5 rounded-lg font-bold uppercase tracking-widest">
                  Сессия
                </span>
              </div>
            )}
            {currentUserRole === 'admin' && managerName === 'custom' && (
              <input
                type="text"
                placeholder="ФИО сотрудника"
                value={managerName === 'custom' ? '' : managerName}
                onChange={(e) => setManagerName(e.target.value)}
                className={`${inputClass} mt-2`}
              />
            )}
          </div>

          <div>
            <label className={labelClass}>ФИО Клиента *</label>
            <div className="relative">
              <User className={iconClass} />
              <input
                type="text"
                placeholder="Имя клиента..."
                value={clientName}
                onChange={(e) => setClientName(e.target.value)}
                className={inputWithIconClass}
              />
            </div>
          </div>
        </div>

        {/* Row 2: Phone + AmoCRM */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div>
            <label className={labelClass}>Номер телефона</label>
            <div className="relative">
              <Phone className={iconClass} />
              <input
                type="tel"
                placeholder="+7 (___) ___-__-__"
                value={clientPhone}
                onChange={(e) => setClientPhone(e.target.value)}
                className={inputWithIconClass}
              />
            </div>
          </div>

          <div>
            <label className={labelClass}>ID Сделки AmoCRM *</label>
            <div className="relative">
              <Link className={iconClass} />
              <input
                type="text"
                placeholder="Например: 42398510"
                value={amocrmLeadId}
                onChange={(e) => setAmocrmLeadId(e.target.value)}
                className={`${inputWithIconClass} font-mono`}
              />
            </div>
          </div>
        </div>

        {/* Row 3: Date + Status */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div>
            <label className={labelClass}>Дата записи *</label>
            <div className="relative">
              <Calendar className={iconClass} />
              <input
                type="date"
                value={bookingDate}
                onChange={(e) => setBookingDate(e.target.value)}
                className={`${inputWithIconClass} cursor-pointer`}
              />
            </div>
          </div>

          <div>
            <label className={labelClass}>Статус записи</label>
            <div className="relative">
              <select
                value={status}
                onChange={(e) => setStatus(e.target.value as LeadStatus)}
                className="w-full px-4 py-3 bg-white border border-indigo-100 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-100 focus:outline-none text-neutral-900 font-medium rounded-xl transition-colors duration-150 text-sm cursor-pointer appearance-none pr-10"
              >
                <option value="booked">📅 Зарегистрирована запись</option>
                <option value="rescheduled">🔄 Запись перенесена</option>
                <option value="showed_up">✅ Визит состоялся</option>
                <option value="no_show">❌ Не пришёл</option>
                <option value="cancelled">🚫 Запись отменена</option>
              </select>
              <ChevronDown className="absolute right-3.5 top-3.5 w-4 h-4 text-indigo-300 pointer-events-none" />
            </div>
          </div>
        </div>

        {/* Prepayment section */}
        <div className="bg-indigo-50/60 border border-indigo-100 p-5 rounded-2xl space-y-4">
          <div className="flex flex-col sm:flex-row sm:items-center gap-5">
            <label className="flex items-center gap-3 cursor-pointer select-none group">
              <div className="relative">
                <input
                  type="checkbox"
                  checked={depositRequired}
                  onChange={(e) => {
                    setDepositRequired(e.target.checked);
                    if (!e.target.checked) { setDepositAmount(0); setDepositPaid(false); }
                  }}
                  className="sr-only peer"
                />
                <div className="w-5 h-5 rounded-md border-2 border-indigo-200 bg-white peer-checked:bg-indigo-600 peer-checked:border-indigo-600 transition-colors duration-150 flex items-center justify-center">
                  {depositRequired && <Check className="w-3 h-3 text-white" />}
                </div>
              </div>
              <span className="text-sm font-semibold text-neutral-700">Требуется предоплата</span>
            </label>

            {depositRequired && (
              <label className="flex items-center gap-3 cursor-pointer select-none">
                <div className="relative">
                  <input
                    type="checkbox"
                    checked={depositPaid}
                    onChange={(e) => setDepositPaid(e.target.checked)}
                    className="sr-only peer"
                  />
                  <div className="w-5 h-5 rounded-md border-2 border-emerald-200 bg-white peer-checked:bg-emerald-500 peer-checked:border-emerald-500 transition-colors duration-150 flex items-center justify-center">
                    {depositPaid && <Check className="w-3 h-3 text-white" />}
                  </div>
                </div>
                <span className="text-sm font-semibold text-neutral-700">Предоплата внесена</span>
              </label>
            )}
          </div>

          {depositRequired && (
            <div className="max-w-xs">
              <label className={labelClass}>Сумма предоплаты (₽)</label>
              <div className="relative">
                <span className="absolute left-3.5 top-3 text-indigo-400 font-bold text-sm">₽</span>
                <input
                  type="number"
                  placeholder="2500"
                  value={depositAmount || ''}
                  onChange={(e) => setDepositAmount(parseInt(e.target.value) || 0)}
                  className="w-full pl-8 pr-4 py-3 bg-white border border-indigo-100 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-100 focus:outline-none text-neutral-900 font-semibold rounded-xl transition-colors duration-150 text-sm"
                />
              </div>
            </div>
          )}
        </div>

        {/* Comments */}
        <div>
          <label className={labelClass}>Примечания</label>
          <div className="relative">
            <FileText className="absolute left-3.5 top-3.5 w-4 h-4 text-indigo-300" />
            <textarea
              rows={2}
              placeholder="Например: просит позвонить заранее для подтверждения"
              value={comments}
              onChange={(e) => setComments(e.target.value)}
              className="w-full pl-10 pr-4 py-3 bg-white border border-indigo-100 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-100 focus:outline-none text-neutral-900 font-medium rounded-xl transition-colors duration-150 text-sm placeholder:text-neutral-300 resize-none"
            />
          </div>
        </div>

        {/* Buttons */}
        <div className="pt-3 border-t border-indigo-50 flex items-center justify-end gap-3">
          {onCancel && (
            <button
              type="button"
              onClick={onCancel}
              className="px-5 py-2.5 bg-white border border-neutral-200 text-neutral-600 hover:text-neutral-900 hover:border-neutral-300 rounded-xl transition-colors duration-150 cursor-pointer text-xs font-bold uppercase tracking-wider"
            >
              Отмена
            </button>
          )}
          <button
            type="submit"
            disabled={isLoading}
            className="px-6 py-2.5 bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 disabled:from-neutral-200 disabled:to-neutral-200 disabled:text-neutral-400 text-white font-bold uppercase tracking-widest rounded-xl transition-colors duration-150 flex items-center gap-2 cursor-pointer text-xs shadow-sm shadow-indigo-200"
          >
            <Check className="w-4 h-4" />
            {isLoading ? 'Сохранение...' : (initialLead ? 'Сохранить' : 'Внести запись')}
          </button>
        </div>
      </form>
    </div>
  );
}

